+
+static char KEY_MEAS_INFO              = 'm';
+
+static char KEY_EXIT                   = 0x1B; // ESC
+
+std::string keyCharToString(char key)
+{
+  if (key == ' ')
+    return "Space";
+  else if (key == 0x1B)
+    return "Esc";
+  else if ((key >= 'a') && (key <= 'z'))
+    return std::string(1, (char)std::toupper(key));
+  else
+    return std::string(1, key);
+}
