+        if (pressed_char == KEY_STEP)
+        {
+          if (!ecal_player->IsMeasurementLoaded())
+          {
+            std::cout << "No measurement loaded. Press [" << keyCharToString(KEY_LOAD_MEAS) << "] to load a measurement." << std::endl;
