+HostTreeItem::HostTreeItem(const QString& host_name)
+  : QAbstractTreeItem()
+  , host_name_(host_name)
+  , publisher_count_(0)
+  , subscriber_count_(0)
+  , data_sent_bytes_(0)
+  , data_received_bytes_(0)
+{
+}
