+QVariant LogModel::data(const QModelIndex &index, int role) const
+{
+  if (index.isValid())
+  {
+    int row = index.row();
+    Columns column = (Columns)index.column();
+
+    if (role == Qt::ItemDataRole::DisplayRole)
+    {
+      switch (column)
+      {
+      case TIME:
+        return timeToString(logs_[row].time);
+      case HOST_NAME:
+        return logs_[row].host_name;
+      case PID:
+        return logs_[row].pid;
+      case PROCESS_NAME:
+        return logs_[row].process_name;
+      case PROCESS_PATH:
+        return logs_[row].process_path;
+      case LOG_LEVEL:
+        return logLevelToString(logs_[row].log_level);
+      case MESSAGE:
+        return logs_[row].message;
+      default:
+        return QVariant();
+      }
+    }
+    else if ((role == ItemDataRoles::FilterRole) || (role == ItemDataRoles::SortRole))
+    {
+      switch (column)
+      {
+      case TIME:
+        return logs_[row].time;
+      case HOST_NAME:
+        return logs_[row].host_name;
+      case PID:
+        return logs_[row].pid;
+      case PROCESS_NAME:
+        return logs_[row].process_name;
+      case PROCESS_PATH:
+        return logs_[row].process_path;
+      case LOG_LEVEL:
+        return logs_[row].log_level;
+      case MESSAGE:
+        return logs_[row].message;
+      default:
+        return QVariant();
+      }
+    }
+    else if (role == Qt::ItemDataRole::ForegroundRole)
+    {
+      switch (column)
+      {
+      case LOG_LEVEL:
+        return logLevelColor(logs_[row].log_level);
+      default:
+        return QVariant();
+      }
+    }
+  }
+  return QVariant();
+}
+
+QString LogModel::logLevelToString(int log_level)
+{
+  switch (log_level)
+  {
+  case eCAL_Logging_eLogLevel::log_level_debug1:
+    return "Debug 1";
+  case eCAL_Logging_eLogLevel::log_level_debug2:
+    return "Debug 2";
+  case eCAL_Logging_eLogLevel::log_level_debug3:
+    return "Debug 3";
+  case eCAL_Logging_eLogLevel::log_level_debug4:
+    return "Debug 4";
+  case eCAL_Logging_eLogLevel::log_level_info:
+    return "Info";
+  case eCAL_Logging_eLogLevel::log_level_warning:
+    return "Warning";
+  case eCAL_Logging_eLogLevel::log_level_error:
