+int TopicTreeModel::mapColumnToItem(int model_column, int tree_item_type) const
+{
+  switch ((TreeItemType)tree_item_type)
+  {
+  case TreeItemType::Topic:
+    return topic_tree_item_column_mapping.at((Columns)(model_column));
